parameters.jsCode:
const raw = $('Read For Archive').first().json.stdout.split('---SPLIT---');
const state = JSON.parse(raw[0]);
const log = raw[1].trim();
const digest = $input.first().json.text || $input.first().json.content?.parts?.[0]?.text || '';

const active = state.session.status === 'active';
const now = new Date();
const il = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Jerusalem' });
const fname = `archive/${il.format(now)}-session${state.session.number}.md`;

if (active) {
  state.session.status = 'ended';
  state.last_session.archive_file = fname;
  state.last_session.ended_at = now.toISOString();
  state.last_session.tomorrow_notes = '';
}

const archive = digest.trim() + '\n\n<!-- RAW-LOG -->\n\n' + log + '\n';

return [{
  json: {
    active,
    fname,
    archiveB64: Buffer.from(archive).toString('base64'),
    stateB64: Buffer.from(JSON.stringify(state, null, 2)).toString('base64')
  }
}];
